mapper.select:
SELECT version_id, file_id, revision_no, user_id, `timestamp`,
       size, mimetype, storage_key, metadata
FROM files_versions
WHERE file_id = #{fileId} AND `timestamp` <= #{targetTimestamp}
ORDER BY `timestamp` DESC, revision_no DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE files_versions
SET metadata = JSON_SET(COALESCE(metadata, '{}'), '$.reason', #{reason})
WHERE version_id = #{versionId}
